@Injectable({ providedIn: 'root' })
export class I18nService {
  private currentLang: LangCode = 'en';

  private static readonly LOCALE_MAP: Record<LangCode, string> = {
    en: 'en-US', es: 'es-ES', fr: 'fr-FR', de: 'de-DE', pt: 'pt-BR',
    zh: 'zh-CN', ja: 'ja-JP', ar: 'ar-SA', hi: 'hi-IN', ko: 'ko-KR',
    it: 'it-IT', ru: 'ru-RU', nl: 'nl-NL', sv: 'sv-SE', pl: 'pl-PL', tr: 'tr-TR',
  };

  setLanguage(lang: string) {
    this.currentLang = (lang in TRANSLATIONS ? lang : 'en') as LangCode;
  }

  getLanguage(): LangCode {
    return this.currentLang;
  }

  /** Get the BCP-47 locale string for the current language (for Intl APIs). */
  getLocale(): string {
    return I18nService.LOCALE_MAP[this.currentLang] || 'en-US';
  }

  /** Get localized month names for the current language. */
  getMonthNames(): string[] {
    const locale = this.getLocale();
    return Array.from({ length: 12 }, (_, i) =>
      new Date(2024, i, 1).toLocaleDateString(locale, { month: 'long' })
    );
  }

  /** Get localized short day labels (Sun, Mon, ...) for the current language. */
  getDayLabels(): string[] {
    const locale = this.getLocale();
    // Generate starting from Sunday (Jan 7, 2024 is a Sunday)
    return Array.from({ length: 7 }, (_, i) =>
      new Date(2024, 0, 7 + i).toLocaleDateString(locale, { weekday: 'short' })
    );
  }

  t(key: string): string {
    return TRANSLATIONS[this.currentLang]?.[key] ?? TRANSLATIONS['en']?.[key] ?? key;
  }
}
